head.b:skin:
/* -----------------------------------------------
Theme Name: DevSpace Minimal (v6 - Responsive Code Block Fix)
Description: Template Blog Komunitas Pengembang Perangkat Lunak Non-Komersial
-------------------------------------------------- */

:root {
    --bg-color: #0f172a;
    --text-color: #e2e8f0;
    --accent-color: #38bdf8;
    --card-bg: rgba(30, 41, 59, 0.75);
    --border-color: #334155;
    --meta-color: #94a3b8;
}

/* Reset & Pengaman Dasar Layout */
* {
    box-sizing: border-box;
}

body {
    background-color: var(--bg-color);
    color: var(--text-color);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif;
    line-height: 1.6;
    margin: 0;
    padding: 0;
    position: relative;
    overflow-x: hidden;
}

/* Lapisan Kanvas Partikel */
#particle-canvas {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    pointer-events: none;
}

a {
    color: var(--accent-color);
    text-decoration: none;
    transition: color 0.2s ease;
}
a:hover {
    color: #7dd3fc;
}

.container {
    width: 100%;
    max-width: 900px;
    margin: 0 auto;
    padding: 20px;
    position: relative;
    z-index: 1;
}

/* Header & Navigasi */
header {
    border-bottom: 1px solid var(--border-color);
    padding-bottom: 20px;
    margin-bottom: 40px;
    display: flex;
    flex-direction: column;
    gap: 15px;
    backdrop-filter: blur(4px);
}
@media(min-width: 600px) {
    header {
        flex-direction: row;
        justify-content: space-between;
        align-items: center;
    }
}
header h1 {
    margin: 0;
    font-size: 1.6rem;
}
header h1 a {
    color: var(--text-color);
}
.nav-links {
    display: flex;
    gap: 15px;
    flex-wrap: wrap;
}
.nav-links a {
    font-size: 0.9rem;
    font-weight: 500;
}

/* Grid Postingan Utama */
.post-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 25px;
    width: 100%;
}

.index-view .post-grid, .archive-view .post-grid {
    @media(min-width: 650px) {
        grid-template-columns: 1fr 1fr;
    }
}
.index-view .post-grid article:first-child {
    @media(min-width: 650px) {
        grid-column: span 2;
    }
}

/* Kartu Postingan (Sudah Dikunci Mencegah Layar Melebar) */
.post {
    background: var(--card-bg);
    padding: 25px;
    border-radius: 8px;
    border: 1px solid var(--border-color);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: transform 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
    backdrop-filter: blur(8px);
    width: 100%;
    max-width: 100%;
    min-width: 0;       /* KUNCI: Mencegah flex child mendorong lebar kontainer */
    overflow: hidden;   /* Mencegah konten meluber keluar kartu */
}
.post:hover {
    transform: translateY(-4px);
    box-shadow: 0 10px 20px -5px rgba(56, 189, 248, 0.15);
    background: rgba(30, 41, 59, 0.9);
    border-color: var(--accent-color);
}
.post-title {
    margin: 0 0 10px 0;
    font-size: 1.5rem;
    line-height: 1.4;
    word-break: break-word;
}
.post-title a {
    color: var(--text-color);
}
.post-meta {
    font-size: 0.8rem;
    color: var(--meta-color);
    margin-bottom: 15px;
}

/* Wadah Isi Artikel */
.post-body {
    width: 100%;
    max-width: 100%;
    min-width: 0;       /* KUNCI: Mengunci lebar ruang artikel */
    overflow-wrap: break-word;
}

/* Pengaturan teks di Halaman Utama (Ringkasan) */
.index-view .post-body, .archive-view .post-body {
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
    font-size: 0.9rem;
    color: #cbd5e1;
    margin-bottom: 20px;
}

/* Pengaturan teks penuh saat artikel dibuka */
.item-view .post-body, .static_page-view .post-body {
    display: block;
    overflow: visible;
    font-size: 1rem;
    color: var(--text-color);
}

.read-more-btn {
    font-size: 0.85rem;
    font-weight: 500;
    align-self: flex-start;
    border: 1px solid var(--accent-color);
    padding: 6px 14px;
    border-radius: 4px;
    transition: all 0.2s ease;
    margin-top: 10px;
}
.read-more-btn:hover {
    background: var(--accent-color);
    color: var(--bg-color) !important;
    text-decoration: none;
}

/* Gaya Kode Khusus Mobile & Desktop (Diperbaiki) */
.post-body p {
    margin: 0 0 1.2em 0;
    word-wrap: break-word;
}
pre, code {
    font-family: "Fira Code", Consolas, Monaco, monospace;
    background-color: #090d16;
    border-radius: 4px;
}
code {
    padding: 2px 6px;
    font-size: 0.9rem;
    color: #f43f5e;
    word-break: break-word;
}
pre {
    padding: 15px;
    border: 1px solid var(--border-color);
    margin: 20px 0;
    display: block;
    width: 100%;
    max-width: 100%;
    overflow-x: auto;       /* Scrollbar horizontal HANYA di dalam box hitam */
    white-space: pre;
    box-sizing: border-box;
}
pre code {
    padding: 0;
    background: transparent;
    color: #e2e8f0;
    white-space: pre;
    display: block;
}

/* Gambar Responsif */
.post-body img {
    max-width: 100%;
    height: auto;
    border-radius: 6px;
}

/* Footer */
footer {
    margin-top: 60px;
    border-top: 1px solid var(--border-color);
    padding-top: 20px;
    font-size: 0.85rem;
    color: var(--meta-color);
    text-align: center;
    backdrop-filter: blur(4px);
}
.contact-info {
    margin-bottom: 10px;
}

body.script:
//
const canvas = document.getElementById('particle-canvas');
const ctx = canvas.getContext('2d');

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}
window.addEventListener('resize', resizeCanvas);
resizeCanvas();

const codeCharacters = ['0', '1', '{', '}', '[', ']', '<', '>', '/', ';', '+', '-', '=', '$'];
const particles = [];
const maxParticles = 60;

class CodeParticle {
    constructor() {
        this.x = Math.random() * canvas.width;
        this.y = Math.random() * canvas.height;
        this.character = codeCharacters[Math.floor(Math.random() * codeCharacters.length)];
        this.speedY = 0.3 + Math.random() * 0.7;
        this.fontSize = 10 + Math.random() * 14;
        this.opacity = 0.05 + Math.random() * 0.15;
    }

    update() {
        this.y += this.speedY;
        if (this.y > canvas.height) {
            this.y = -20;
            this.x = Math.random() * canvas.width;
            this.opacity = 0.05 + Math.random() * 0.15;
        }
    }

    draw() {
        ctx.fillStyle = `rgba(56, 189, 248, ${this.opacity})`;
        ctx.font = `${this.fontSize}px monospace`;
        ctx.fillText(this.character, this.x, this.y);
    }
}

for (let i = 0; i < maxParticles; i++) {
    particles.push(new CodeParticle());
}

function animate() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    particles.forEach(particle => {
        particle.update();
        particle.draw();
    });
    requestAnimationFrame(animate);
}
animate();
//
